{
    "prompts": [
        {
            "name": "mindmap_prompt",
            "description": "用于生成思维导图的提示",
            "parameters": []
        },
        {
            "name": "translate_expert_prompt",
            "description": "输入要翻译的语句，以及要翻译的目标语言，以及要翻译的风格,生成专业的翻译提示词",
            "parameters": [
                {
                    "name": "language",
                    "description": "要翻译的目标语种,输入语言的英文单词或者中文即可",
                    "required": true
                },
                {
                    "name": "mode",
                    "description": "可用风格: [{'语言风格': '默认风格', '对应mode参数': 'default'}, {'语言风格': '学术风格', '对应mode参数': 'academic'}, {'语言风格': '口语化', '对应mode参数': 'spoken'}, {'语言风格': '书面化', '对应mode参数': 'written'}, {'语言风格': '文艺风格', '对应mode参数': 'literature'}, {'语言风格': '意译', '对应mode参数': 'paraphrase'}]",
                    "required": true
                }
            ]
        },
        {
            "name": "WebSearchOnly",
            "description": "Web search only prompt template - uses only web search without local knowledge base",
            "parameters": []
        },
        {
            "name": "BaseKnowledgeBaseOnly",
            "description": "仅使用知识库而不使用网络搜索的提示词, 属于基本的简单业务",
            "parameters": [
                {
                    "name": "knowledge_base_id_list",
                    "description": "使用知识库做问答的过程中，本轮限定的使用知识库 ID 列表，如果为空，则默认是使用所有知识库，如果非空，则必须只使用列表中指定的知识库",
                    "required": false
                }
            ]
        },
        {
            "name": "BaseKnowledgeBaseInsight",
            "description": "对用户的知识库做出一个有洞察力的insight和总结, 属于基本的简单业务",
            "parameters": [
                {
                    "name": "knowledge_base_id_list",
                    "description": "对用户的知识库做出insight和总结的过程中，本轮限定的使用知识库 ID 列表，如果为空，则默认是对所有知识库进行insight分析，如果非空，则必须只能对使用列表中指定的知识库进行insight分析，不能涉及到列表之外的知识库",
                    "required": false
                }
            ]
        },
        {
            "name": "BaseKnowledgeBaseAndNetwork",
            "description": "同时使用知识库和网络搜索的提示词, 属于基本的简单业务",
            "parameters": [
                {
                    "name": "knowledge_base_id_list",
                    "description": "使用知识库和网络搜索做问答的过程中，本轮限定的使用知识库 ID 列表，如果为空，则默认是使用用户的所有知识库，如果非空，在使用知识库查询的过程必须只使用列表中指定的知识库，不能涉及到列表之外的知识库",
                    "required": false
                }
            ]
        },
        {
            "name": "PremiumDeepResearch",
            "description": "使用deepresearch模式, 同时使用知识库和网络搜索以及序列化思考工具, 属于高级业务",
            "parameters": [
                {
                    "name": "knowledge_base_id_list",
                    "description": "使用deepresearch模式做问答的过程中，本轮限定的使用知识库 ID 列表，如果为空，则默认是使用用户的所有知识库，如果非空，在使用知识库查询的过程必须只使用列表中指定的知识库，不能涉及到列表之外的知识库",
                    "required": false
                }
            ]
        },
        {
            "name": "csv_analysis_prompt",
            "description": "提示词：指导大模型在拿到 CSV 文件后如何调用本工具进行分析",
            "parameters": []
        },
        {
            "name": "document_generation_prompt",
            "description": "提示词：指导大模型生成多种格式的文档",
            "parameters": []
        },
        {
            "name": "report_generation_prompt",
            "description": "提示词：指导大模型使用 produce_report 工具生成研究报告",
            "parameters": []
        },
        {
            "name": "email_query_result",
            "description": "Concise addon prompt for email delivery - to be appended to other task prompts",
            "parameters": []
        },
        {
            "name": "sequentialthinking_prompt",
            "description": "\n    工具详细用法描述。\n    ",
            "parameters": []
        },
        {
            "name": "complex_task_planning",
            "description": "\n    复杂任务规划提示词，用于涉及多个工具组合的复杂任务\n    ",
            "parameters": []
        }
    ]
}

